SELECT * FROM transaction_enose;
SELECT * FROM transaction_enose ORDER BY date_time DESC LIMIT 10;
SELECT device_id, type, date_time FROM transaction_enose;
SELECT COUNT(*) AS total_transaksi FROM transaction_enose;
SELECT * FROM transaction_enose ORDER BY date_time DESC LIMIT 1;
SELECT * FROM transaction_enose ORDER BY date_time ASC LIMIT 1;
SELECT DISTINCT type FROM transaction_enose;
SELECT DISTINCT device_id FROM transaction_enose;
SELECT * FROM transaction_enose WHERE type = 'greentea';
SELECT COUNT(*) AS total FROM transaction_enose WHERE type = 'greentea';
SELECT * FROM transaction_enose WHERE device_id = 'e-nose_1';
SELECT COUNT(*) AS total FROM transaction_enose WHERE device_id = 'e-nose_1';
SELECT * FROM transaction_enose WHERE value LIKE '%Class:Baik%';
SELECT COUNT(*) AS total_baik FROM transaction_enose WHERE value LIKE '%Class:Baik%';
SELECT * FROM transaction_enose WHERE value LIKE '%Cacat Mutu%';
SELECT COUNT(*) AS total_cacat FROM transaction_enose WHERE value LIKE '%Cacat Mutu%';
SELECT * FROM transaction_enose WHERE value LIKE '%Multiclass:A%';
SELECT COUNT(*) AS total FROM transaction_enose WHERE value LIKE '%Multiclass:D%';
SELECT * FROM transaction_enose WHERE type = 'greentea' AND value LIKE '%Cacat Mutu%' AND device_id = 'e-nose_1';
SELECT * FROM transaction_enose WHERE DATE(date_time) = '2025-02-07';
SELECT * FROM transaction_enose WHERE YEAR(date_time) = 2025 AND MONTH(date_time) = 2;
SELECT * FROM transaction_enose WHERE YEAR(date_time) = 2025;
SELECT * FROM transaction_enose WHERE date_time BETWEEN '2025-06-01 00:00:00' AND '2025-06-30 23:59:59';
SELECT MIN(date_time) AS transaksi_pertama FROM transaction_enose;
SELECT MAX(date_time) AS transaksi_terakhir FROM transaction_enose;
SELECT * FROM transaction_enose WHERE TIME(date_time) BETWEEN '10:00:00' AND '12:00:00';
SELECT AVG(CAST(SUBSTRING_INDEX(SUBSTRING_INDEX(value, 'Score:', -1), ',', 1) AS DECIMAL(5,2))) AS avg_score FROM transaction_enose;
SELECT MAX(CAST(SUBSTRING_INDEX(SUBSTRING_INDEX(value, 'Score:', -1), ',', 1) AS DECIMAL(5,2))) AS max_score FROM transaction_enose;
SELECT MIN(CAST(SUBSTRING_INDEX(SUBSTRING_INDEX(value, 'Score:', -1), ',', 1) AS DECIMAL(5,2))) AS min_score FROM transaction_enose;
SELECT device_id, COUNT(*) AS total FROM transaction_enose GROUP BY device_id ORDER BY total DESC;
SELECT type, COUNT(*) AS total FROM transaction_enose GROUP BY type ORDER BY total DESC;
SELECT DATE(date_time) AS tanggal, COUNT(*) AS total FROM transaction_enose GROUP BY tanggal ORDER BY tanggal;
SELECT DATE_FORMAT(date_time, '%Y-%m') AS bulan, COUNT(*) AS total FROM transaction_enose GROUP BY bulan ORDER BY bulan;
SELECT SUM(CASE WHEN value LIKE '%Class:Baik%' THEN 1 ELSE 0 END) AS total_baik, SUM(CASE WHEN value LIKE '%Cacat Mutu%' THEN 1 ELSE 0 END) AS total_cacat_mutu FROM transaction_enose;
SELECT SUM(CASE WHEN value LIKE '%Multiclass:A%' THEN 1 ELSE 0 END) AS A, SUM(CASE WHEN value LIKE '%Multiclass:B%' THEN 1 ELSE 0 END) AS B, SUM(CASE WHEN value LIKE '%Multiclass:C%' THEN 1 ELSE 0 END) AS C, SUM(CASE WHEN value LIKE '%Multiclass:D%' THEN 1 ELSE 0 END) AS D, SUM(CASE WHEN value LIKE '%Multiclass:E%' THEN 1 ELSE 0 END) AS E FROM transaction_enose;
SELECT type, AVG(CAST(SUBSTRING_INDEX(SUBSTRING_INDEX(value, 'Score:', -1), ',', 1) AS DECIMAL(5,2))) AS avg_score FROM transaction_enose GROUP BY type ORDER BY avg_score DESC;
SELECT device_id, COUNT(*) AS total FROM transaction_enose GROUP BY device_id ORDER BY total DESC LIMIT 1;
SELECT DATE(date_time) AS tanggal, COUNT(*) AS total FROM transaction_enose WHERE device_id = 'e-nose_1' AND YEAR(date_time) = 2025 AND MONTH(date_time) = 7 GROUP BY tanggal ORDER BY tanggal;
SELECT DATE(date_time) AS tanggal, COUNT(*) AS total FROM transaction_enose GROUP BY tanggal ORDER BY total DESC LIMIT 1;
SELECT ROUND(COUNT(CASE WHEN value LIKE '%Cacat Mutu%' THEN 1 END) * 100.0 / COUNT(*), 2) AS persen_cacat_mutu FROM transaction_enose;
SELECT * FROM transaction_enose WHERE type = 'greentea' AND value LIKE '%Class:Baik%' AND device_id = 'e-nose_1' AND YEAR(date_time) = 2025 AND MONTH(date_time) = 6 ORDER BY date_time DESC;
SELECT device_id, COUNT(*) AS total_cacat FROM transaction_enose WHERE value LIKE '%Cacat Mutu%' GROUP BY device_id HAVING total_cacat > 10 ORDER BY total_cacat DESC;
SELECT DATE_FORMAT(date_time, '%Y-%m') AS bulan, COUNT(*) AS total FROM transaction_enose GROUP BY bulan HAVING total > 20 ORDER BY bulan;
SELECT * FROM transaction_enose WHERE DATE(date_time) = (SELECT DATE(date_time) FROM transaction_enose GROUP BY DATE(date_time) ORDER BY COUNT(*) DESC LIMIT 1);
SELECT device_id, SUM(CASE WHEN value LIKE '%Class:Baik%' THEN 1 ELSE 0 END) AS total_baik, SUM(CASE WHEN value LIKE '%Cacat Mutu%' THEN 1 ELSE 0 END) AS total_cacat FROM transaction_enose GROUP BY device_id ORDER BY device_id;
SELECT * FROM transaction_object_detection;
SELECT * FROM transaction_object_detection ORDER BY detection_time DESC LIMIT 10;
SELECT COUNT(*) AS total_record FROM transaction_object_detection;
SELECT * FROM transaction_object_detection ORDER BY detection_time DESC LIMIT 1;
SELECT * FROM transaction_object_detection ORDER BY detection_time ASC LIMIT 1;
SELECT DISTINCT type FROM transaction_object_detection;
SELECT DISTINCT device_id FROM transaction_object_detection;
SELECT * FROM transaction_object_detection WHERE type = 'car';
SELECT * FROM transaction_object_detection WHERE type = 'people';
SELECT COUNT(*) AS total_record FROM transaction_object_detection WHERE type = 'bus';
SELECT SUM(value) AS total_car FROM transaction_object_detection WHERE type = 'car';
SELECT SUM(value) AS total_people FROM transaction_object_detection WHERE type = 'people';
SELECT AVG(value) AS avg_bicycle FROM transaction_object_detection WHERE type = 'bicycle';
SELECT * FROM transaction_object_detection WHERE value > 10 ORDER BY value DESC;
SELECT * FROM transaction_object_detection WHERE value < 5;
SELECT * FROM transaction_object_detection WHERE type = 'car' AND value > 5 ORDER BY detection_time;
SELECT * FROM transaction_object_detection WHERE device_id = 'edge_1';
SELECT COUNT(*) AS total FROM transaction_object_detection WHERE device_id = 'edge_1';
SELECT * FROM transaction_object_detection WHERE DATE(detection_time) = '2025-02-19';
SELECT SUM(value) AS total_objek FROM transaction_object_detection WHERE DATE(detection_time) = '2025-02-19';
SELECT MIN(detection_time) AS deteksi_pertama FROM transaction_object_detection;
SELECT MAX(detection_time) AS deteksi_terakhir FROM transaction_object_detection;
SELECT * FROM transaction_object_detection WHERE YEAR(detection_time) = 2025 AND MONTH(detection_time) = 2;
SELECT * FROM transaction_object_detection WHERE TIME(detection_time) BETWEEN '13:00:00' AND '14:00:00';
SELECT SUM(value) AS total_semua_objek FROM transaction_object_detection;
SELECT MAX(value) AS max_objek FROM transaction_object_detection;
SELECT MIN(value) AS min_objek FROM transaction_object_detection;
SELECT AVG(value) AS rata_rata_objek FROM transaction_object_detection;
SELECT type, SUM(value) AS total FROM transaction_object_detection GROUP BY type ORDER BY total DESC;
SELECT type, COUNT(*) AS jumlah_record FROM transaction_object_detection GROUP BY type ORDER BY jumlah_record DESC;
SELECT DATE(detection_time) AS tanggal, SUM(value) AS total FROM transaction_object_detection GROUP BY tanggal ORDER BY tanggal;
SELECT device_id, SUM(value) AS total FROM transaction_object_detection GROUP BY device_id ORDER BY total DESC;
SELECT type, AVG(value) AS avg_per_snapshot FROM transaction_object_detection GROUP BY type ORDER BY avg_per_snapshot DESC;
SELECT HOUR(detection_time) AS jam, SUM(value) AS total FROM transaction_object_detection WHERE DATE(detection_time) = '2025-02-19' GROUP BY jam ORDER BY jam;
SELECT DATE(detection_time) AS tanggal, type, SUM(value) AS total FROM transaction_object_detection GROUP BY tanggal, type ORDER BY tanggal, type;
SELECT type, SUM(value) AS total FROM transaction_object_detection GROUP BY type ORDER BY total DESC LIMIT 1;
SELECT type, COUNT(*) AS jumlah_record FROM transaction_object_detection GROUP BY type ORDER BY jumlah_record DESC LIMIT 1;
SELECT HOUR(detection_time) AS jam, SUM(value) AS total FROM transaction_object_detection WHERE type = 'people' GROUP BY jam ORDER BY total DESC LIMIT 1;
SELECT SUM(CASE WHEN type = 'car' THEN value ELSE 0 END) AS total_car, SUM(CASE WHEN type = 'bus' THEN value ELSE 0 END) AS total_bus, SUM(CASE WHEN type = 'bicycle' THEN value ELSE 0 END) AS total_bicycle, SUM(CASE WHEN type = 'people' THEN value ELSE 0 END) AS total_people FROM transaction_object_detection;
SELECT type, SUM(value) AS total, ROUND(SUM(value) * 100.0 / (SELECT SUM(value) FROM transaction_object_detection), 2) AS persentase FROM transaction_object_detection GROUP BY type ORDER BY total DESC;
SELECT type, SUM(value) AS total FROM transaction_object_detection WHERE device_id = 'edge_1' GROUP BY type ORDER BY total DESC;
SELECT type, SUM(value) AS total FROM transaction_object_detection GROUP BY type HAVING total > 50 ORDER BY total DESC;
SELECT DATE(detection_time) AS tanggal, SUM(value) AS total FROM transaction_object_detection GROUP BY tanggal HAVING total > 100 ORDER BY tanggal;
SELECT * FROM transaction_object_detection WHERE value > (SELECT AVG(value) FROM transaction_object_detection) ORDER BY value DESC;
SELECT DATE(detection_time) AS tanggal, SUM(value) AS total FROM transaction_object_detection GROUP BY tanggal ORDER BY total DESC LIMIT 1;
SELECT 'transaction_enose' AS tabel, COUNT(*) AS total FROM transaction_enose UNION ALL SELECT 'transaction_object_detection' AS tabel, COUNT(*) AS total FROM transaction_object_detection;
SELECT date_time AS waktu, 'enose' AS sumber, type, value FROM transaction_enose WHERE device_id = 'edge_1' UNION ALL SELECT detection_time AS waktu, 'object_detection' AS sumber, type, CAST(value AS CHAR) FROM transaction_object_detection WHERE device_id = 'edge_1' ORDER BY waktu;
SELECT DISTINCT device_id FROM transaction_enose WHERE device_id NOT IN (SELECT DISTINCT device_id FROM transaction_object_detection);
SELECT tanggal, SUM(total) AS total_gabungan FROM (SELECT DATE(date_time) AS tanggal, COUNT(*) AS total FROM transaction_enose GROUP BY DATE(date_time) UNION ALL SELECT DATE(detection_time) AS tanggal, COUNT(*) AS total FROM transaction_object_detection GROUP BY DATE(detection_time)) AS gabungan GROUP BY tanggal ORDER BY tanggal;
SELECT DISTINCT device_id FROM transaction_enose WHERE device_id IN (SELECT DISTINCT device_id FROM transaction_object_detection);